import{c as s,Q as l,j as n,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"App Store、TestFlight、Google Play 与国内应用市场","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/08-AppStore-TestFlight-GooglePlay与国内应用市场.md","filePath":"mobileCommonLearning/08-AppStore-TestFlight-GooglePlay与国内应用市场.md","lastUpdated":1780912084000}'),t={name:"mobileCommonLearning/08-AppStore-TestFlight-GooglePlay与国内应用市场.md"};function i(p,a,o,r,d,h){return l(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="app-store、testflight、google-play-与国内应用市场" tabindex="-1">App Store、TestFlight、Google Play 与国内应用市场 <a class="header-anchor" href="#app-store、testflight、google-play-与国内应用市场" aria-label="Permalink to &quot;App Store、TestFlight、Google Play 与国内应用市场&quot;">​</a></h1><p>移动端分发不是一个按钮。不同商店和渠道的规则、审核、灰度、账号权限都不一样。</p><p>一句话先记住:<strong>商店是分发入口,渠道是运营现实;移动端发版必须按渠道治理。</strong></p><hr><h2 id="一、几个入口" tabindex="-1">一、几个入口 <a class="header-anchor" href="#一、几个入口" aria-label="Permalink to &quot;一、几个入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>入口</th><th>作用</th></tr></thead><tbody><tr><td>App Store</td><td>iOS 正式分发</td></tr><tr><td>TestFlight</td><td>iOS 内测 / 外测</td></tr><tr><td>Google Play</td><td>Android 国际主渠道</td></tr><tr><td>Google Play Internal / Closed / Open testing</td><td>Android 测试轨道</td></tr><tr><td>国内应用市场</td><td>华为、小米、OPPO、vivo、荣耀、应用宝等</td></tr><tr><td>官网 APK</td><td>自有 Android 分发</td></tr><tr><td>企业分发</td><td>公司内部安装</td></tr></tbody></table><p>每个入口都要单独管理账号、权限、材料、版本和发布记录。</p><hr><h2 id="二、app-store" tabindex="-1">二、App Store <a class="header-anchor" href="#二、app-store" aria-label="Permalink to &quot;二、App Store&quot;">​</a></h2><p>App Store 关注:</p><ul><li>Bundle ID</li><li>版本号和 build</li><li>隐私信息</li><li>权限用途</li><li>截图和描述</li><li>内购 / 订阅合规</li><li>Sign in with Apple 要求</li><li>审核问题回复</li></ul><p>正式包通常流程:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Archive</span></span>
<span class="line"><span>  -&gt; Upload to App Store Connect</span></span>
<span class="line"><span>  -&gt; TestFlight 验证</span></span>
<span class="line"><span>  -&gt; 填写版本信息</span></span>
<span class="line"><span>  -&gt; Submit for Review</span></span>
<span class="line"><span>  -&gt; Approved</span></span>
<span class="line"><span>  -&gt; Manual / Automatic release</span></span></code></pre></div><p>上架前必须用 TestFlight 真机跑核心流程。</p><hr><h2 id="三、testflight" tabindex="-1">三、TestFlight <a class="header-anchor" href="#三、testflight" aria-label="Permalink to &quot;三、TestFlight&quot;">​</a></h2><p>TestFlight 适合:</p><ul><li>内部 QA</li><li>外部小规模测试</li><li>审核前验证</li><li>回归 release 包行为</li></ul><p>注意:</p><ul><li>TestFlight 包接近正式环境,但仍不是 App Store 正式分发。</li><li>外部测试也可能需要审核。</li><li>build 有有效期。</li><li>推送、IAP、登录等要按沙盒 / 生产边界测试。</li></ul><p>不要把 debug 包给测试人员长期使用。测试发布链路就要测 TestFlight。</p><hr><h2 id="四、google-play" tabindex="-1">四、Google Play <a class="header-anchor" href="#四、google-play" aria-label="Permalink to &quot;四、Google Play&quot;">​</a></h2><p>Google Play 常见轨道:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Internal testing</span></span>
<span class="line"><span>Closed testing</span></span>
<span class="line"><span>Open testing</span></span>
<span class="line"><span>Production</span></span></code></pre></div><p>现代新项目通常:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AAB</span></span>
<span class="line"><span>Play App Signing</span></span>
<span class="line"><span>Internal testing</span></span>
<span class="line"><span>staged rollout</span></span></code></pre></div><p>注意:</p><ul><li>版本号 <code>versionCode</code> 必须递增。</li><li>target SDK 会受政策约束。</li><li>权限、数据安全、广告 ID 等材料要填。</li><li>生产发布可以分阶段扩大比例。</li></ul><hr><h2 id="五、国内应用市场" tabindex="-1">五、国内应用市场 <a class="header-anchor" href="#五、国内应用市场" aria-label="Permalink to &quot;五、国内应用市场&quot;">​</a></h2><p>国内渠道的特点:</p><ul><li>渠道多</li><li>审核口径不完全一致</li><li>签名变更需要人工处理</li><li>软件著作权、ICP备案、隐私政策、权限说明经常被要求</li><li>厂商推送、联运、加固、广告 SDK 可能引入额外审核点</li></ul><p>常见渠道:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>华为 AppGallery</span></span>
<span class="line"><span>小米应用商店</span></span>
<span class="line"><span>OPPO 软件商店</span></span>
<span class="line"><span>vivo 应用商店</span></span>
<span class="line"><span>荣耀应用市场</span></span>
<span class="line"><span>应用宝</span></span>
<span class="line"><span>百度手机助手</span></span>
<span class="line"><span>360 手机助手</span></span></code></pre></div><p>国内项目必须有渠道台账。</p><hr><h2 id="六、渠道台账" tabindex="-1">六、渠道台账 <a class="header-anchor" href="#六、渠道台账" aria-label="Permalink to &quot;六、渠道台账&quot;">​</a></h2><p>至少记录:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>渠道名</span></span>
<span class="line"><span>后台地址</span></span>
<span class="line"><span>账号归属</span></span>
<span class="line"><span>负责人</span></span>
<span class="line"><span>应用 ID / 包名</span></span>
<span class="line"><span>当前线上版本</span></span>
<span class="line"><span>签名指纹</span></span>
<span class="line"><span>审核材料</span></span>
<span class="line"><span>上次发版时间</span></span>
<span class="line"><span>特殊规则</span></span>
<span class="line"><span>客服 / 工单入口</span></span></code></pre></div><p>没有台账,离职或事故时会直接失控。</p><hr><h2 id="七、官网-apk" tabindex="-1">七、官网 APK <a class="header-anchor" href="#七、官网-apk" aria-label="Permalink to &quot;七、官网 APK&quot;">​</a></h2><p>官网 APK 适合:</p><ul><li>国内无 Play 环境</li><li>企业客户下载</li><li>灰度内测</li><li>特定渠道需求</li></ul><p>但风险高:</p><ul><li>用户可能安装旧包</li><li>下载链接可能被替换</li><li>没有商店审核兜底</li><li>签名泄漏后伪造包风险更大</li></ul><p>官网 APK 必须配:</p><ul><li>HTTPS</li><li>文件 hash</li><li>版本号展示</li><li>下载来源提示</li><li>后端异常版本拦截</li></ul><hr><h2 id="八、什么时候会出事故" tabindex="-1">八、什么时候会出事故 <a class="header-anchor" href="#八、什么时候会出事故" aria-label="Permalink to &quot;八、什么时候会出事故&quot;">​</a></h2><ol><li>App Store 审核过了,但 TestFlight 没测核心支付流程。</li><li>Google Play target SDK 不达标,临近截止才发现。</li><li>国内某渠道拒审,但没人知道账号在哪。</li><li>官网 APK CDN 被旧版本缓存。</li><li>同一版本不同渠道包行为不一致。</li><li>渠道上传了错包,用户覆盖到错误环境。</li></ol><hr><h2 id="九、检查清单" tabindex="-1">九、检查清单 <a class="header-anchor" href="#九、检查清单" aria-label="Permalink to &quot;九、检查清单&quot;">​</a></h2><ul><li>[ ] App Store Connect 账号和权限是否清楚</li><li>[ ] Play Console 账号和权限是否清楚</li><li>[ ] 国内渠道后台是否有台账</li><li>[ ] 每个渠道当前版本是否记录</li><li>[ ] 是否统一使用 release 包测试</li><li>[ ] 官网 APK 是否有 hash 和可信来源说明</li><li>[ ] 审核材料是否集中维护</li><li>[ ] 渠道特殊规则是否记录</li></ul><hr><h2 id="十、心智模型" tabindex="-1">十、心智模型 <a class="header-anchor" href="#十、心智模型" aria-label="Permalink to &quot;十、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App Store 管 iOS 正式分发</span></span>
<span class="line"><span>TestFlight 管 iOS 测试分发</span></span>
<span class="line"><span>Google Play 管 Android 国际分发和签名托管</span></span>
<span class="line"><span>国内渠道需要逐个治理</span></span>
<span class="line"><span>官网 APK 是自担风险的分发</span></span></code></pre></div><p>下一篇 09 讲灰度发布、分阶段发布与回滚策略。</p>`,59)])])}const u=s(t,[["render",i]]);export{g as __pageData,u as default};
